const item = $input.first().json;

// Helper: toma el primer valor "util" descartando undefined/null/vacios y la cadena literal "undefined"/"null"
const pick = (...vals) => {
  for (const v of vals) {
    if (v === undefined || v === null) continue;
    const s = String(v).trim();
    if (!s) continue;
    const low = s.toLowerCase();
    if (low === 'undefined' || low === 'null') continue;
    return s;
  }
  return '';
};

// Intenta parsear la query en dos modos:
// 1) Etiquetado:   "Nombre: Joham, Servicio: Corte + Barba, Fecha: 2026-04-15, Hora: 09:00"
// 2) Posicional:   "Joham, Corte de Cabello, 2026-04-16, 14:00" (orden depende de la accion)
const query = typeof item.query === 'string' ? item.query.trim() : '';
const partes = query ? query.split(',').map(p => p.trim()).filter(Boolean) : [];

const parsedLabeled = {};
let hayEtiquetas = false;
for (const part of partes) {
  const colonIdx = part.indexOf(':');
  if (colonIdx === -1) continue;
  const rawKey = part.substring(0, colonIdx).trim().toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  const value = part.substring(colonIdx + 1).trim();
  // Solo aceptar como etiqueta si la clave es alfabetica (evita que '10:00' o '2026-04-16' se confundan con etiquetas)
  if (rawKey && value && /^[a-z]+$/.test(rawKey)) {
    parsedLabeled[rawKey] = value;
    hayEtiquetas = true;
  }
}

// accion viene fija desde el flujo 01; si no, se infiere abajo.
let accion = pick(item.accion, parsedLabeled.accion).toLowerCase();

// Orden posicional segun accion
const ordenPorAccion = {
  agendar:         ['nombre','servicio','fecha','hora'],
  cancelar:        ['nombre','fecha'],
  consultar:       ['fecha'],
  guardar_cliente: ['nombre']
};

const parsedPositional = {};
if (!hayEtiquetas && accion && ordenPorAccion[accion]) {
  const campos = ordenPorAccion[accion];
  for (let i = 0; i < campos.length && i < partes.length; i++) {
    parsedPositional[campos[i]] = partes[i];
  }
}

// Fusion: item (fields del tool) -> labeled -> positional
const nombre   = pick(item.nombre,   parsedLabeled.nombre,   parsedPositional.nombre);
const servicio = pick(item.servicio, parsedLabeled.servicio, parsedPositional.servicio);
const fecha    = pick(item.fecha,    parsedLabeled.fecha,    parsedPositional.fecha);
const hora     = pick(item.hora,     parsedLabeled.hora,     parsedPositional.hora);
const numero   = pick(item.numero,   parsedLabeled.numero);

// Inferir accion si aun esta vacia
if (!accion) {
  if (servicio && hora)         accion = 'agendar';
  else if (nombre && fecha)     accion = 'cancelar';
  else if (nombre && !fecha)    accion = 'guardar_cliente';
  else                          accion = 'consultar';
}

return [{
  json: { accion, nombre, servicio, fecha, hora, numero }
}];

// Duraciones del servicio (minutos). El evento del calendario dura exactamente lo que dura el servicio.
const duraciones = {
  'corte': 40, 'corte de cabello': 40,
  'corte + barba': 55, 'corte barba': 55, 'corte+barba': 55,
  'corte ninos': 35, 'corte niños': 35, 'ninos': 35, 'niños': 35,
  'afeitado': 30, 'afeitado tradicional': 30,
  'diseno barba': 30, 'diseño barba': 30, 'diseño de barba': 30,
  'tratamiento': 55, 'tratamiento capilar': 55,
  'masaje': 45, 'masaje cuero cabelludo': 45
};
const TZ_OFFSET = '-05:00'; // America/Bogota

const item = $input.first().json;

// Validar datos minimos
const falta = [];
if (!item.fecha)    falta.push('fecha');
if (!item.hora)     falta.push('hora');
if (!item.nombre)   falta.push('nombre');
if (!item.servicio) falta.push('servicio');
if (falta.length) {
  return [{ json: { ...item, _error: true, resultado: `Faltan datos para agendar: ${falta.join(', ')}.` } }];
}

// Validar formato fecha (YYYY-MM-DD) y hora (HH:mm)
if (!/^\d{4}-\d{2}-\d{2}$/.test(item.fecha)) {
  return [{ json: { ...item, _error: true, resultado: `Fecha con formato invalido: ${item.fecha}. Debe ser YYYY-MM-DD.` } }];
}
if (!/^\d{2}:\d{2}$/.test(item.hora)) {
  return [{ json: { ...item, _error: true, resultado: `Hora con formato invalido: ${item.hora}. Debe ser HH:mm.` } }];
}

// Limite de 5 dias de anticipacion
const tz = 'America/Bogota';
const hoyStr = new Date().toLocaleString('en-CA', { timeZone: tz, year: 'numeric', month: '2-digit', day: '2-digit' });
const hoy = new Date(hoyStr + 'T00:00:00');
const limite = new Date(hoy);
limite.setDate(limite.getDate() + 5);
const fechaCita = new Date(item.fecha + 'T00:00:00');
if (fechaCita < hoy) {
  return [{ json: { ...item, _error: true, resultado: 'No se puede agendar en fechas pasadas.' } }];
}
if (fechaCita > limite) {
  const dias = ['domingo','lunes','martes','miercoles','jueves','viernes','sabado'];
  const meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
  const limLegible = `${dias[limite.getDay()]} ${limite.getDate()} de ${meses[limite.getMonth()]}`;
  return [{ json: { ...item, _error: true, resultado: `Solo manejamos agenda para los proximos 5 dias. La fecha mas lejana disponible es ${limLegible}.` } }];
}

const servicioKey = item.servicio.toLowerCase();
const duracion = duraciones[servicioKey] || 40;

// Calcular hora fin sumando la duracion en minutos, manteniendo misma fecha salvo overflow
const [hh, mm] = item.hora.split(':').map(Number);
const totalMin = hh * 60 + mm + duracion;
const finHH = Math.floor(totalMin / 60) % 24;
const finMM = totalMin % 60;
const diaExtra = Math.floor(totalMin / (60 * 24));

let fechaFin = item.fecha;
if (diaExtra > 0) {
  const d = new Date(item.fecha + 'T00:00:00');
  d.setDate(d.getDate() + diaExtra);
  const pad = n => String(n).padStart(2,'0');
  fechaFin = `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;
}

const pad2 = n => String(n).padStart(2,'0');
const fechaHoraInicio = `${item.fecha}T${item.hora}:00${TZ_OFFSET}`;
const fechaHoraFin    = `${fechaFin}T${pad2(finHH)}:${pad2(finMM)}:00${TZ_OFFSET}`;

return [{
  json: {
    ...item,
    duracion,
    fechaHoraInicio,
    fechaHoraFin,
    titulo: `${item.nombre} - ${item.servicio}`,
    descripcion: `Telefono: ${item.numero || 'N/A'}`
  }
}];

const item = $input.first().json;
const inicio = item.start?.dateTime || item.fechaHoraInicio || '';
return [{
  json: {
    resultado: `Cita confirmada: ${item.summary || item.titulo}. Inicio: ${inicio}.`
  }
}];

const eventos = $input.all();
const entrada = $('Parsear Datos').item.json;

const ahora = new Date();
const limite = new Date(ahora.getTime() + 2 * 60 * 60 * 1000);

if (eventos.length === 0) {
  return [{ json: { resultado: 'No se encontro ninguna cita para ' + (entrada.nombre || 'el cliente') + ' en esa fecha.', citaId: null } }];
}

const evento = eventos[0].json;
const inicioCita = new Date(evento.start?.dateTime || evento.start?.date);

if (inicioCita < limite) {
  return [{ json: { resultado: 'No se puede cancelar. La cita es en menos de 2 horas. Llama al 3334324220.', citaId: null } }];
}

return [{ json: { resultado: 'ok', citaId: evento.id, resumen: evento.summary } }];

const item = $input.first().json;
const nombre = item.nombre || 'cliente';
return [{ json: { resultado: `Nombre guardado correctamente: ${nombre}.` } }];

// Obtener eventos del dia (puede ser 0 items si no hay citas)
const items = $input.all();
const eventos = items.filter(e => e.json && e.json.start).map(e => e.json);
const fecha = $('Parsear Datos').item.json.fecha;

// Horarios reales de la barberia
// Lunes-Viernes: 09:00-12:00 y 14:00-18:00
// Sabado: 10:00-12:00 y 14:00-18:00
const fechaDate = new Date(fecha + 'T12:00:00');
const dia = fechaDate.getDay(); // 0=dom, 6=sab

if (dia === 0) {
  return [{ json: { resultado: 'La barberia no abre los domingos. Elige otro dia.' } }];
}

const turnos = dia === 6
  ? [{ inicio: 10, fin: 12 }, { inicio: 14, fin: 18 }]
  : [{ inicio: 9, fin: 12 }, { inicio: 14, fin: 18 }];

const slots = [];
for (const turno of turnos) {
  for (let h = turno.inicio; h < turno.fin; h++) {
    slots.push(`${String(h).padStart(2,'0')}:00`);
    slots.push(`${String(h).padStart(2,'0')}:30`);
  }
}

// Marcar slots ocupados por eventos existentes
const ocupados = new Set();
for (const ev of eventos) {
  const start = new Date(ev.start.dateTime || ev.start.date);
  const end = new Date(ev.end?.dateTime || ev.end?.date || start);
  // Marcar cada slot de 30 min que cae dentro del rango del evento
  for (const slot of slots) {
    const [sh, sm] = slot.split(':').map(Number);
    const slotDate = new Date(fecha + 'T' + slot + ':00-05:00');
    if (slotDate >= start && slotDate < end) {
      ocupados.add(slot);
    }
  }
}

const libres = slots.filter(s => !ocupados.has(s));

const dias = ['domingo','lunes','martes','miercoles','jueves','viernes','sabado'];
const meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
const fechaLegible = `${dias[dia]} ${fechaDate.getDate()} de ${meses[fechaDate.getMonth()]}`;

const respuesta = libres.length > 0
  ? `Horarios disponibles el ${fechaLegible}: ${libres.join(', ')}`
  : `No hay horarios disponibles el ${fechaLegible}. Elige otra fecha.`;

return [{ json: { resultado: respuesta } }];

// Verificar que el horario solicitado no se superponga con eventos existentes en el calendario.
const citaData = $('Calcular Fin Cita').item.json;
const eventos = $input.all().filter(e => e.json && e.json.start);

const inicioNuevo = new Date(citaData.fechaHoraInicio);
const finNuevo    = new Date(citaData.fechaHoraFin);

for (const ev of eventos) {
  const evStart = new Date(ev.json.start.dateTime || ev.json.start.date);
  const evEnd   = new Date(ev.json.end?.dateTime || ev.json.end?.date || evStart);
  // Hay conflicto si los rangos se superponen
  if (inicioNuevo < evEnd && finNuevo > evStart) {
    const hOcupada = `${String(evStart.getHours()).padStart(2,'0')}:${String(evStart.getMinutes()).padStart(2,'0')}`;
    const hFinOcupada = `${String(evEnd.getHours()).padStart(2,'0')}:${String(evEnd.getMinutes()).padStart(2,'0')}`;
    return [{ json: { resultado: `Ese horario ya esta ocupado (${hOcupada} - ${hFinOcupada}). Por favor elige otra hora.` } }];
  }
}

// Sin conflicto: pasar los datos de la cita para crear el evento
return [{ json: { ...citaData, _disponible: true } }];
